// Rack C – AI inference / training workload

let cpuLoad = Math.min(100, 70 + Math.random() * 25); // 70–95%
let ambient = 25 + Math.random() * 1.5;
let inlet = ambient + cpuLoad * 0.08;
let exhaust = inlet + 10 + Math.random() * 3;

const payload = {
  rack_id: "RackC",
  workload_type: "ai_inference",
  cpu_util: Number(cpuLoad.toFixed(2)),
  power_kw: Number((1.8 + cpuLoad * 0.02).toFixed(2)),
  ambient_temp_c: Number(ambient.toFixed(2)),
  inlet_temp_c: Number(inlet.toFixed(2)),
  exhaust_temp_c: Number(exhaust.toFixed(2)),
  fan_speed_rpm: Math.round(3200 + cpuLoad * 40),
  humidity: Number((42 + Math.random() * 5).toFixed(2))
};

msg.payload =
  "mosquitto_pub -d -q 1 " +
  "-h 192.168.29.21 -p 1883 " +
  "-t v1/devices/me/telemetry " +
  "-u svngr613xtq8072xa97i " +
  "-m \"" + JSON.stringify(payload).replace(/"/g, '\\"') + "\"";

return msg;
